// An ElevenLabs server tool POSTs its parameters as a flat JSON body:
// { service, date, time }. (`body.args ?? body` below also accepts the nested
// shape, so the same flow still works if you test it with a wrapped payload.)
// Turn the caller's words into a concrete 1-hour slot in the salon timezone.
const TZ_OFFSET = '+08:00';            // Singapore
const OPEN_HOUR = 8;                   // 8:00 AM
const CLOSE_HOUR = 21;                 // 9:00 PM (last slot starts 20:00)

const body = $input.first().json.body ?? {};
const args = body.args ?? body;        // tolerate a flat test payload

const service = (args.service || 'Appointment').toString();
const date = (args.date || '').toString();   // expected YYYY-MM-DD
const time = (args.time || '').toString();   // expected HH:MM (24h)

if (!/^\d{4}-\d{2}-\d{2}$/.test(date) || !/^\d{2}:\d{2}$/.test(time)) {
  return [{ json: { valid: false, service, date, time,
    speak: 'I did not catch the day and time. What day and what time would you like?' } }];
}

const start = `${date}T${time}:00${TZ_OFFSET}`;
const end = new Date(new Date(start).getTime() + 60 * 60 * 1000).toISOString();
const hour = Number(time.slice(0, 2));

// Sunday = closed; outside opening hours = closed.
const dow = new Date(start).getDay();
if (dow === 0 || hour < OPEN_HOUR || hour >= CLOSE_HOUR) {
  return [{ json: { valid: false, service, date, time, start, end,
    speak: 'We are open Monday to Saturday, eight in the morning to nine at night. Would another time work?' } }];
}

return [{ json: { valid: true, service, date, time, start, end } }];

// The Calendar node returns one item per event in the window (none = free).
// alwaysOutputData gives us a single empty item when there are no events.
const events = $input.all().filter(i => i.json && i.json.id);
const slot = $('Parse Slot').first().json;
const free = events.length === 0;

const spokenTime = new Date(slot.start).toLocaleTimeString('en-SG', {
  hour: 'numeric', minute: '2-digit', hour12: true, timeZone: 'Asia/Singapore',
});

return [{ json: {
  available: free,
  service: slot.service,
  date: slot.date,
  time: slot.time,
  start: slot.start,
  end: slot.end,
  // `speak` is what Nina reads out. Keep it one short sentence.
  speak: free
    ? `Yes, ${spokenTime} on ${slot.date} is free for a ${slot.service}. Shall I book it?`
    : `Sorry, ${spokenTime} is already taken. Would an hour earlier or later work?`,
} }];

// The ElevenLabs book_appointment tool POSTs { service, date, time, name, phone }.
const TZ_OFFSET = '+08:00';
const body = $input.first().json.body ?? {};
const args = body.args ?? body;

const service = (args.service || 'Appointment').toString();
const date = (args.date || '').toString();
const time = (args.time || '').toString();
const name = (args.name || 'Guest').toString();
const phone = (args.phone || '').toString();

if (!/^\d{4}-\d{2}-\d{2}$/.test(date) || !/^\d{2}:\d{2}$/.test(time)) {
  return [{ json: { valid: false,
    speak: 'I still need the day and the time before I can book that.' } }];
}

const start = `${date}T${time}:00${TZ_OFFSET}`;
const end = new Date(new Date(start).getTime() + 60 * 60 * 1000).toISOString();

return [{ json: { valid: true, service, date, time, name, phone, start, end,
  summary: `${service} - ${name}`,
  description: `Booked by Nina (ElevenLabs voice agent).\nService: ${service}\nCustomer: ${name}\nPhone: ${phone}` } }];

// Confirm back to ElevenLabs. The whole JSON is handed to the agent; `speak` is
// the line it reads aloud.
const ev = $input.first().json;
const slot = $('Build Event').first().json;

const spokenTime = new Date(slot.start).toLocaleTimeString('en-SG', {
  hour: 'numeric', minute: '2-digit', hour12: true, timeZone: 'Asia/Singapore',
});

return [{ json: {
  booked: true,
  eventId: ev.id ?? null,
  htmlLink: ev.htmlLink ?? null,
  speak: `Done. I've booked your ${slot.service} on ${slot.date} at ${spokenTime} under ${slot.name}. See you then!`,
} }];
